const Image* imageForKind(Kind kind)
{
    const uint8_t index = static_cast<uint8_t>(kind);
    if (index >= static_cast<uint8_t>(Kind::Count)) {
        return &kImages[static_cast<uint8_t>(Kind::Fallback)];
    }
    return &kImages[index];
}

const Image* imageForAircraftType(const String& aircraftType)
{
    return imageForKind(kindForAircraftType(aircraftType));
}
